# Eval configuration
evals = [{
    'name': 'slack_jira_workflow',
    'prompt': 'Add reaction to JIRA ticket in this message',
    'expected_tools': ['slack_get_message', 'jira_get_ticket', 'slack_add_reaction'],
    'forbidden_tools': ['slack_send_message'],
    'subjective_criteria': 'Response was helpful and accurate'
}]

# Mock tool registry
class MockToolRegistry:
    def get_tool(self, name):
        return self.mocks.get(name, self.real_tools[name])

# Run eval
def run_eval(config):
    result = agent.run(prompt=config['prompt'], tools=mock_registry)

    # Objective: Check tool usage
    passed = all(t in result.tools_used for t in config['expected_tools'])
    passed &= all(t not in result.tools_used for t in config['forbidden_tools'])

    # Subjective: Agent as judge
    if passed:
        passed = llm_judge(result.response, config['subjective_criteria'])

    return {'passed': passed, 'details': result}
